  constructor(size) {
    this.size = size;
    this.arr = new Array(size);
    this.front = 0;
    this.rear = 0;
    this.count = 0;
  }

  isEmpty() {
    return this.count === 0;
  }

  isFull() {
    return this.count === this.size;
  }

  enqueue(value) {
    if (this.isFull()) return false;

    this.arr[this.rear] = value;
    this.rear = (this.rear + 1) % this.size;
    this.count += 1;
    return true;
  }

